parameters.jsCode:
const items = $items("MySQL Search Listings By Category");

if (!items.length) {
  return [
    {
      json: {
        reply_text: "Sorry, I could not find any listings in that category right now."
      }
    }
  ];
}

const category = items[0].json.category || "selected";

const reply =
  `Here are the latest ${category} listings:\n\n` +
  items.map((item, index) => {
    return `${index + 1}. ${item.json.title}\nDescription: ${item.json.description}\nContact: ${item.json.contact_info}\nLocation: ${item.json.location}`;
  }).join("\n\n");

return [
  {
    json: {
      reply_text: reply
    }
  }
];

